#include<string>
#include<iostream>
#include<algorithm>
using namespace std;

const int N = 30;
struct Node
{
	int lch, rch;
}tree[N];

string postorder(string mid, string pre)
{
	int n = mid.size();
	if(n <= 1) return mid;
	int p = -1;
	for(int i = 0; i < n; i++)
		if(mid[i] == pre[0])
			p = i;
	string ans;
	ans += postorder(mid.substr(0, p), pre.substr(1, p));
	ans += postorder(mid.substr(p + 1), pre.substr(p + 1));
	ans += pre[0];
	return ans;
}

int main(){
	string mid, pre;
	cin >> mid >> pre;
	cout << postorder(mid, pre);
	return 0;
}
